import axiosInstance from "../axiosConfig";
import { useFormik } from "formik";
import { useState } from "react";
import { useCookies } from "react-cookie";
import { useNavigate } from "react-router-dom";

export function AdminLogin() {
    let navigate = useNavigate();
    const [cookies, setCookie, removeCookie] = useCookies(['admin-id']);

    const formik = useFormik({
        initialValues: {
            UserId: '',
            Password: ''
        },
        onSubmit: (admin) => {
            axiosInstance.get('/get-admin')
                .then(response => {
                    const [fetchedAdmin] = response.data;

                    if (!fetchedAdmin) {
                        alert("No admin data found.");
                        return;
                    }

                    if (admin.UserId === fetchedAdmin.UserId && admin.Password === fetchedAdmin.Password) {
                        setCookie('admin-id', admin.UserId, { path: '/' });
                        navigate('/admin-dashboard');
                        window.location.reload();
                    } else {
                        navigate('/admin-error');
                    }
                })
                .catch(() => {
                    alert("Unable to connect to server.");
                });
        }
    });

    return (
        <div className="d-flex justify-content-center align-items-center" style={{ height: '60vh' }}>
            <form className="w-25" onSubmit={formik.handleSubmit}>
                <div className="text-center bi bi-person-circle mb-3">Admin Login</div>
                <dl>
                    <dt>Admin Id</dt>
                    <dd><input type="text" name="UserId" onChange={formik.handleChange} className="form-control" required /></dd>
                    <dt>Password</dt>
                    <dd><input type="password" name="Password" onChange={formik.handleChange} className="form-control" required /></dd>
                </dl>
                <button className="btn btn-danger w-100">Login</button>
            </form>
        </div>
    );
}
